import type { FC, CSSProperties } from 'react';
import React from 'react';
import clsx from 'clsx';
import { useClassPrefix } from '../config-provider/hooks';

export interface ContentProps extends React.PropsWithChildren<unknown> {
  style?: CSSProperties;
  className?: string;
}

const Content: FC<ContentProps> = ({ children, style, className }) => {
  const prefix = useClassPrefix();

  const classnames = clsx(
    {
      [`${prefix}__tooltip-content`]: true,
    },
    className,
  );

  return (
    <div className={classnames} role="tooltip" style={style}>
      {children}
    </div>
  );
};

export default Content;
